256	           when 24 => c := 'O';
257	           when 25 => c := 'P';
258	           when 26 => c := 'Q';
259	           when 27 => c := 'R';
260	           when 28 => c := 'S';
261	           when 29 => c := 'T';
262	           when 30 => c := 'U';
